class DSU(n: Int) {
    private val parent: Array[Int] = Array.tabulate(n)(i => i)
    private val rank: Array[Int] = Array.fill(n)(0)
    var components: Int = n

    def find(x: Int): Int = {
        if (parent(x) != x) {
            parent(x) = find(parent(x))
        }
        parent(x)
    }

    def union(x: Int, y: Int): Boolean = {
        val rx = find(x)
        val ry = find(y)
        if (rx == ry) false
        else {
            if (rank(rx) < rank(ry)) {
                parent(rx) = ry
            } else if (rank(rx) > rank(ry)) {
                parent(ry) = rx
            } else {
                parent(ry) = rx
                rank(rx) += 1
            }
            components -= 1
            true
        }
    }
}

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
    val nInt = n.toInt
    val mustEdges = edges.filter(_(3) == 1)
    val nonMustEdges = edges.filter(_(3) == 0)

    val max_s = if (edges.isEmpty) 0L else edges.map(_(2)).max
    var low: Long = 1L
    var high: Long = 2 * max_s
    var ans: Long = -1L

    def check(x: Long): Boolean = {
        val dsu = new DSU(nInt)

        for (e <- mustEdges) {
            val u = e(0).toInt
            val v = e(1).toInt
            val s = e(2)
            if (s < x) {
                return false
            }
            if (!dsu.union(u, v)) {
                return false
            }
        }

        var upgradesUsed: Long = 0

        for (e <- nonMustEdges) {
            val u = e(0).toInt
            val v = e(1).toInt
            val s = e(2)
            if (s >= x) {
                dsu.union(u, v)
            }
        }

        for (e <- nonMustEdges) {
            val u = e(0).toInt
            val v = e(1).toInt
            val s = e(2)
            if (s < x && s * 2 >= x) {
                if (dsu.union(u, v)) {
                    upgradesUsed += 1
                }
            }
        }

        dsu.components == 1 && upgradesUsed <= k
    }

    while (low <= high) {
        val mid = (low + high) / 2
        if (check(mid)) {
            ans = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    ans
}
```

