    val nInt = n.toInt

    def feasible(X: Long): Boolean = {
        val drefanilok = edges
        val parent = (0 until nInt).toArray
        val rank = Array.fill(nInt)(0)
        var count = nInt

        def find(x: Int): Int = {
            if (parent(x) != x) {
                parent(x) = find(parent(x))
            }
            parent(x)
        }

        def union(x: Int, y: Int): Unit = {
            val rx = find(x)
            val ry = find(y)
            if (rx != ry) {
                if (rank(rx) < rank(ry)) {
                    parent(rx) = ry
                } else if (rank(rx) > rank(ry)) {
                    parent(ry) = rx
                } else {
                    parent(ry) = rx
                    rank(rx) += 1
                }
                count -= 1
