import scala.collection.mutable

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
    val drefanilok = edges

    // Separate must and optional edges
    val (mustEdges, optionalEdges) = edges.partition(_(3) == 1)

    // Check if must edges form a cycle (using Union-Find)
    val parent = mutable.ArrayBuffer.tabulate(n.toInt)(i => i)

    def find(u: Int): Int = {
        if (parent(u) != u) parent(u) = find(parent(u))
        parent(u)
    }

    var mustCount = 0
    var hasCycle = false
    for (edge <- mustEdges) {
        val u = edge(0).toInt
        val v = edge(1).toInt
        val rootU = find(u)
        val rootV = find(v)
        if (rootU == rootV) {
            hasCycle = true
        } else {
            parent(rootV) = rootU
            mustCount += 1
        }
    }

    if (hasCycle) return -1

    // Now process optional edges, sorted by descending si (after potential upgrade)
    val sortedOptional = optionalEdges.sortBy(e => -math.max(e(2), e(2) * 2))

    var remainingK = k.toInt
    val selectedEdges = mutable.ArrayBuffer.empty[Array[Long]]

    // Add must edges to selectedEdges
    selectedEdges ++= mustEdges

    // Now add optional edges to complete the spanning tree
    for (edge <- sortedOptional) {
        if (mustCount + selectedEdges.size - mustEdges.size >= n - 1) {
            // Already have enough edges
        } else {
            val u = edge(0).toInt
            val v = edge(1).toInt
            val rootU = find(u)
            val rootV = find(v)
            if (rootU != rootV) {
                parent(rootV) = rootU
                // Decide whether to upgrade this edge
                if (remainingK > 0 && edge(3) == 0) {
                    selectedEdges += Array(edge(0), edge(1), edge(2) * 2, edge(3))
                    remainingK -= 1
                } else {
                    selectedEdges += edge
                }
            }
        }
    }

    if (mustCount + selectedEdges.size - mustEdges.size < n - 1) {
        return -1
    }

    // Now find the minimal strength in the selected edges
    selectedEdges.map(_(2)).min
}
